TOLERANCE = 0.01

def _rel_l2(a, b):
    a, b = np.asarray(a, np.float64).ravel(), np.asarray(b, np.float64).ravel()
    if a.shape != b.shape: return float('inf')
    return float(np.linalg.norm(a - b) / (np.linalg.norm(b) + 1e-8))

def main():
    try:
        import onnx, onnx2torch, torch
        model = onnx2torch.convert(onnx.load(_io.BytesIO(_ONNX_BYTES))).eval()
        x = torch.from_numpy(INPUT)

        with torch.no_grad():
            ref = model(x)
            if isinstance(ref, (list, tuple)): ref = ref[0]
            ref = ref.float().numpy().ravel()

        compiled = torch.compile(model)
        with torch.no_grad():
            result = compiled(x)
            if isinstance(result, (list, tuple)): result = result[0]
            result = result.float().numpy().ravel()
    except Exception as e:
        print(f"[error] torch.compile: {e}")
        sys.exit(2)

    diff = _rel_l2(result, ref)
    print(f"Expected (pytorch_eager) at idx 0: {ref.ravel()[0]:.6f}")
    print(f"Got (torch.compile) at idx 0: {result.ravel()[0]:.6f}")  # expected=-0.000019, got=0.000000
    print(f"rel L2(compiled vs eager) = {diff:.6e}")
    if diff > TOLERANCE:
        print("BUG REPRODUCED")
        sys.exit(0)
    print("not reproduced")
    sys.exit(1)

if __name__ == "__main__":
    main()
